function scoreColor(s) {
  if (s >= 9)   return { bg:"#e8f9f0", text:"#0a6640", bar:"#1db86a", label:"Excelente" };
  if (s >= 7.5) return { bg:"#e8f0ff", text:"#1a3cb8", bar:"#4166f5", label:"Muito Bom" };
  if (s >= 6)   return { bg:"#fffae8", text:"#7a5200", bar:"#f0a500", label:"Regular" };
  if (s >= 4)   return { bg:"#fff1e8", text:"#8a2e00", bar:"#f06a00", label:"Insatisfatório" };
  return              { bg:"#ffeaea", text:"#8a0000", bar:"#e82020", label:"Crítico" };
}

function initials(n) { return (n||"").split(" ").slice(0,2).map(x=>x[0]).join("").toUpperCase(); }
function avatarHue(n) { return ((n||"").charCodeAt(0) * 47) % 360; }

function generatePDF(ev, logoB64) {
  const c = scoreColor(ev.score || ev.media || 0);
  const rows = (ev.criteria||[]).map(cr => {
    const cc = scoreColor(cr.nota || cr.score || 0);
    return `<tr>
      <td style="padding:8px 12px;border-bottom:1px solid #f0f0f0;font-size:12px;color:#222">${cr.criterio||cr.id}</td>
      <td style="padding:8px 12px;border-bottom:1px solid #f0f0f0;text-align:center;font-weight:700;font-size:16px;color:${cc.bar}">${cr.nota||cr.score||0}</td>
      <td style="padding:8px 12px;border-bottom:1px solid #f0f0f0;text-align:center"><span style="background:${cc.bg};color:${cc.text};padding:3px 10px;border-radius:20px;font-size:11px;font-weight:600">${cc.label}</span></td>
      <td style="padding:8px 12px;border-bottom:1px solid #f0f0f0;font-size:11px;color:#555;line-height:1.5">${cr.obs||""}</td>
    </tr>`;
  }).join("");
  const sigImg = ev.signature
    ? `<img src="${ev.signature}" style="max-height:56px;border:1px solid #ddd;border-radius:4px;margin-top:8px"/>`
    : `<div style="border-bottom:2px solid #222;width:200px;margin-top:44px"></div>`;
  const html = `<!DOCTYPE html><html lang="pt-BR"><head><meta charset="UTF-8"><title>Feedback — ${ev.agent||ev.name}</title>
  <style>*{box-sizing:border-box}body{font-family:'Segoe UI',Arial,sans-serif;background:#fff;color:#111;margin:0;padding:36px}
  @media print{body{padding:16px}button{display:none!important}}</style></head><body>
  <div style="display:flex;align-items:center;justify-content:space-between;padding-bottom:18px;border-bottom:3px solid #5b21b6;margin-bottom:24px">
    <img src="data:image/jpeg;base64,${logoB64}" style="height:60px"/>
    <div style="text-align:right"><div style="font-size:22px;font-weight:700;color:#5b21b6">Relatório de Monitoria</div><div style="font-size:12px;color:#888;margin-top:2px">QA Telecom · ${ev.date||""}</div></div>
  </div>
  <div style="background:linear-gradient(135deg,#f5f0ff,#ede9fe);border-radius:12px;padding:18px 22px;margin-bottom:22px;border-left:4px solid #7c3aed">
    <div style="font-size:20px;font-weight:700;color:#3b0764">${ev.agent||ev.name}</div>
    <div style="font-size:13px;color:#6d28d9;margin-top:5px">Empresa: <b>${ev.company}</b> &nbsp;·&nbsp; Protocolo: <b>${ev.protocol||"—"}</b> &nbsp;·&nbsp; Tipo: <b>${ev.type||"Ligação"}</b></div>
  </div>
  <table style="width:100%;border-collapse:collapse;margin-bottom:22px">
    <thead><tr style="background:#5b21b6;color:#fff">
      <th style="padding:10px 12px;text-align:left;font-size:12px;border-radius:4px 0 0 0">Critério</th>
      <th style="padding:10px 12px;text-align:center;font-size:12px;width:60px">Nota</th>
      <th style="padding:10px 12px;text-align:center;font-size:12px;width:130px">Desempenho</th>
      <th style="padding:10px 12px;text-align:left;font-size:12px;border-radius:0 4px 0 0">Observações</th>
    </tr></thead>
    <tbody>${rows}</tbody>
  </table>
  <div style="background:${c.bg};border-radius:12px;padding:16px 22px;display:flex;justify-content:space-between;align-items:center;margin-bottom:20px">
    <div style="font-size:14px;color:${c.text};font-weight:500">Média Final</div>
    <div><span style="font-size:40px;font-weight:700;color:${c.bar}">${(ev.score||ev.media||0).toFixed?.(1) || ev.score||ev.media||0}</span> <span style="font-size:15px;font-weight:600;color:${c.text}">${c.label}</span></div>
  </div>
  <div style="display:grid;grid-template-columns:1fr 1fr;gap:14px;margin-bottom:22px">
    <div style="background:#f0fdf4;border:1px solid #86efac;border-radius:10px;padding:14px"><div style="font-size:10px;font-weight:700;color:#166534;letter-spacing:.05em;margin-bottom:5px">PONTOS FORTES</div><div style="font-size:13px;color:#15803d;line-height:1.6">${ev.pontos_fortes||ev.pontos_fortes||"—"}</div></div>
    <div style="background:#fff7ed;border:1px solid #fed7aa;border-radius:10px;padding:14px"><div style="font-size:10px;font-weight:700;color:#9a3412;letter-spacing:.05em;margin-bottom:5px">PONTOS A DESENVOLVER</div><div style="font-size:13px;color:#c2410c;line-height:1.6">${ev.pontos_dev||ev.pontos_desenvolver||"—"}</div></div>
  </div>
  <div style="background:#f5f0ff;border:1px solid #c4b5fd;border-radius:10px;padding:16px;margin-bottom:30px">
    <div style="font-size:10px;font-weight:700;color:#5b21b6;letter-spacing:.05em;margin-bottom:6px">FEEDBACK AO COLABORADOR</div>
    <div style="font-size:14px;color:#3b0764;line-height:1.7;font-style:italic">"${ev.feedback||"—"}"</div>
  </div>
  <div style="border-top:1px solid #e5e7eb;padding-top:22px;display:flex;justify-content:space-between;align-items:flex-end">
    <div><div style="font-size:11px;color:#9ca3af;margin-bottom:4px">Assinatura do Colaborador</div>${sigImg}<div style="font-size:13px;color:#374151;margin-top:8px;font-weight:500">${ev.agent||ev.name}</div></div>
    <div style="text-align:right;font-size:11px;color:#9ca3af"><div style="font-weight:600;color:#6d28d9;font-size:13px">Sirius Assessoria e Consultoria</div><div style="margin-top:3px">Data: ${ev.date||""}</div></div>
  </div>
  <div style="margin-top:28px;text-align:center"><button onclick="window.print()" style="background:#5b21b6;color:#fff;border:none;border-radius:8px;padding:11px 32px;font-size:14px;font-weight:600;cursor:pointer;letter-spacing:.03em">Imprimir / Salvar como PDF</button></div>
  </body></html>`;
  const w = window.open("","_blank");
  w.document.write(html); w.document.close();
}

function AudioPlayer({ src, fileName }) {
  const ref = useRef(); const [play,setPlay]=useState(false); const [cur,setCur]=useState(0); const [dur,setDur]=useState(0); const [vol,setVol]=useState(1); const [spd,setSpd]=useState(1);
  useEffect(()=>{const a=ref.current;if(!a)return;const t=()=>setCur(a.currentTime);const m=()=>setDur(a.duration||0);const e=()=>setPlay(false);a.addEventListener("timeupdate",t);a.addEventListener("loadedmetadata",m);a.addEventListener("ended",e);return()=>{a.removeEventListener("timeupdate",t);a.removeEventListener("loadedmetadata",m);a.removeEventListener("ended",e);};},[src]);
  useEffect(()=>()=>{if(src?.startsWith("blob:"))URL.revokeObjectURL(src);},[src]);
  const fmt=s=>{if(!s||isNaN(s))return"0:00";return`${Math.floor(s/60)}:${String(Math.floor(s%60)).padStart(2,"0")}`};
  return(
    <div style={{background:"#1a0533",border:"1px solid #4c1d95",borderRadius:10,padding:"14px 18px",marginBottom:14}}>
      <audio ref={ref} src={src} preload="metadata"/>
      <div style={{display:"flex",alignItems:"center",gap:8,marginBottom:10}}>
        <span style={{fontSize:16}}>🎵</span>
        <span style={{fontSize:12,color:"#a78bfa",flex:1,overflow:"hidden",textOverflow:"ellipsis",whiteSpace:"nowrap"}}>{fileName}</span>
        {dur>0&&<span style={{fontSize:11,color:"#6d28d9"}}>{fmt(dur)}</span>}
      </div>
      <div style={{position:"relative",height:4,background:"#2d1b69",borderRadius:2,marginBottom:12,cursor:"pointer"}}>
        <div style={{height:"100%",width:`${dur?(cur/dur)*100:0}%`,background:"linear-gradient(90deg,#7c3aed,#a855f7)",borderRadius:2,pointerEvents:"none"}}/>
        <input type="range" min={0} max={dur||1} step={0.1} value={cur} onChange={e=>{const v=parseFloat(e.target.value);ref.current.currentTime=v;setCur(v);}} style={{position:"absolute",inset:0,opacity:0,cursor:"pointer",width:"100%",margin:0,height:"100%"}}/>
      </div>
      <div style={{display:"flex",alignItems:"center",justifyContent:"space-between",gap:8,flexWrap:"wrap"}}>
        <div style={{display:"flex",alignItems:"center",gap:8}}>
          <button onClick={()=>{const a=ref.current;a.currentTime=Math.max(0,a.currentTime-10);}} style={{background:"none",border:"none",color:"#a78bfa",cursor:"pointer",fontSize:18,padding:0}}>⏮</button>
          <button onClick={()=>{const a=ref.current;if(play){a.pause();setPlay(false);}else{a.play().catch(()=>{});setPlay(true);}}} style={{width:36,height:36,borderRadius:"50%",background:"linear-gradient(135deg,#7c3aed,#a855f7)",border:"none",cursor:"pointer",fontSize:15,color:"#fff",fontWeight:900}}>{play?"⏸":"▶"}</button>
          <button onClick={()=>{const a=ref.current;a.currentTime=Math.min(dur,a.currentTime+10);}} style={{background:"none",border:"none",color:"#a78bfa",cursor:"pointer",fontSize:18,padding:0}}>⏭</button>
          <span style={{fontSize:11,color:"#6d28d9"}}>{fmt(cur)} / {fmt(dur)}</span>
        </div>
        <div style={{display:"flex",alignItems:"center",gap:6}}>
          <input type="range" min={0} max={1} step={0.05} value={vol} onChange={e=>{const v=parseFloat(e.target.value);ref.current.volume=v;setVol(v);}} style={{width:56,accentColor:"#a855f7"}}/>
          {[0.75,1,1.5,2].map(s=><button key={s} onClick={()=>{ref.current.playbackRate=s;setSpd(s);}} style={{background:spd===s?"#7c3aed":"#2d1b69",color:spd===s?"#fff":"#a78bfa",border:"none",borderRadius:4,padding:"2px 6px",fontSize:10,cursor:"pointer"}}>{s}x</button>)}
        </div>
      </div>
    </div>
  );
}

